param([Parameter(Mandatory=$true)][string]$IncomingRoot,[Parameter(Mandatory=$true)][string]$RunId)
$ErrorActionPreference='Stop';$target='execution';$policy='nora.metaeditor_cli_success_v1';$editor='C:\Program Files\Darwinex MetaTrader 5\MetaEditor64.exe';$expectedBuild='5.0.0.5836';$runtime='NoraPhase2ExecutionRuntimeV1.mqh';$tester='NoraPhase2ExecutionTesterCanaryV1.mq5';$inputName='execution_compile_input_v1.json';$root=Join-Path $env:USERPROFILE 'NoraPhase2ExecutionValidation\compile-v1';$run=Join-Path $root $RunId;$evidence=Join-Path $run 'evidence'
function FileHash($p){(Get-FileHash -LiteralPath $p -Algorithm SHA256).Hash.ToLowerInvariant()}
if(Test-Path $run){throw 'occupied compile destination'};New-Item -ItemType Directory $evidence -Force|Out-Null
try{$inputPath=Join-Path $IncomingRoot $inputName;if(!(Test-Path $inputPath)){throw 'missing compile input'};$input=Get-Content $inputPath -Raw|ConvertFrom-Json;if($input.target_identifier -ne $target -or $input.compiler_policy -ne $policy){throw 'wrong compile input target or policy'};$runtimePath=Join-Path $IncomingRoot $runtime;$testerPath=Join-Path $IncomingRoot $tester;if(!(Test-Path $runtimePath) -or !(Test-Path $testerPath)){throw 'missing source'};if((FileHash $runtimePath) -ne $input.runtime_sha256 -or (FileHash $testerPath) -ne $input.tester_sha256){throw 'source hash mismatch'};if(!(Test-Path $editor)){throw 'missing MetaEditor'};$build=(Get-Item $editor).VersionInfo.FileVersion;if($build -ne $expectedBuild){throw 'unexpected MetaEditor build'};$compileDir=Join-Path $run 'compile';New-Item -ItemType Directory $compileDir|Out-Null;Copy-Item $runtimePath (Join-Path $compileDir $runtime);Copy-Item $testerPath (Join-Path $compileDir $tester);$program=Join-Path $compileDir $tester;$ex5=Join-Path $compileDir 'NoraPhase2ExecutionTesterCanaryV1.ex5';$log=Join-Path $compileDir 'compile.log';$prior=$null;if(Test-Path $ex5){$prior=@{path=$ex5;sha256=FileHash $ex5;size=(Get-Item $ex5).Length};Remove-Item $ex5 -Force};$start=(Get-Date).ToUniversalTime();$args=@('/compile:"'+$program+'"','/log:"'+$log+'"');$p=Start-Process -FilePath $editor -ArgumentList $args -PassThru;if(!$p.WaitForExit(120000)){$p.Kill();throw 'compiler timeout'};$end=(Get-Date).ToUniversalTime();if(!(Test-Path $log)){throw 'missing compiler log'};$lines=Get-Content $log;$resultLine=@($lines|?{$_ -match '^Result:'})|select -Last 1;if(!$resultLine -or $resultLine -notmatch 'Result:\s*(\d+) errors,\s*(\d+) warnings'){throw 'incomplete compiler log'};$errors=[int]$matches[1];$warnings=[int]$matches[2];if($errors -ne 0 -or $warnings -ne 0){throw 'compiler diagnostics'};if(!(Test-Path $ex5)){throw 'missing EX5'};$item=Get-Item $ex5;$fresh=($item.LastWriteTimeUtc -ge $start);if(!$fresh){throw 'stale EX5'};$decision=if($p.ExitCode -eq 0){'accepted_zero'}elseif($p.ExitCode -eq 1){'accepted_metaeditor_5836_one'}else{throw 'unsupported compiler exit'};Copy-Item $log (Join-Path $evidence 'compile.log');Copy-Item $ex5 (Join-Path $evidence 'NoraPhase2ExecutionTesterCanaryV1.ex5');$record=[ordered]@{schema_version='nora.execution_compiler_output_v1';target_identifier=$target;compile_input_identity=$input.compile_input_identity;runtime_sha256=FileHash $runtimePath;tester_sha256=FileHash $testerPath;metaeditor_executable=$editor;observed_metaeditor_build=$build;exact_command=($editor+' '+($args -join ' '));invocation_start_utc=$start.ToString('o');invocation_completion_utc=$end.ToString('o');raw_process_exit=$p.ExitCode;normalized_result='success';compiler_policy=$policy;policy_decision=$decision;log_path='compile.log';log_size=(Get-Item (Join-Path $evidence 'compile.log')).Length;log_sha256=FileHash (Join-Path $evidence 'compile.log');warning_count=0;warnings=@();error_count=0;errors=@();ex5_path='NoraPhase2ExecutionTesterCanaryV1.ex5';ex5_size=(Get-Item (Join-Path $evidence 'NoraPhase2ExecutionTesterCanaryV1.ex5')).Length;ex5_modification_utc=$item.LastWriteTimeUtc.ToString('o');ex5_sha256=FileHash (Join-Path $evidence 'NoraPhase2ExecutionTesterCanaryV1.ex5');stale_ex5_disposition=if($prior){'preexisting_target_removed'}else{'none_present'};freshness_proof=[ordered]@{preexisting_ex5_removed_or_isolated=$true;produced_after_invocation_start=$fresh;single_unambiguous_ex5=$true};completion_state='completed';failure_reason=$null};$record|ConvertTo-Json -Depth 8|Set-Content (Join-Path $evidence 'compiler_record.json') -Encoding utf8;@{schema_version='nora.execution_compile_evidence_manifest_v1';target_identifier=$target;compile_input_identity=$input.compile_input_identity}|ConvertTo-Json|Set-Content (Join-Path $evidence 'compile_evidence_manifest.json') -Encoding utf8;$inventory=@();foreach($x in @(@('compiler_record.json','compiler_record'),@('compile.log','compiler_log'),@('NoraPhase2ExecutionTesterCanaryV1.ex5','ex5'),@('compile_evidence_manifest.json','compile_evidence_manifest'))){$f=Join-Path $evidence $x[0];$inventory+=@{path=$x[0];role=$x[1];sha256=FileHash $f;size=(Get-Item $f).Length}};$inventory|ConvertTo-Json|Set-Content (Join-Path $evidence 'inventory.json') -Encoding utf8;Write-Output ($evidence)}catch{Remove-Item $run -Recurse -Force -ErrorAction SilentlyContinue;throw}
